class Solution {
public:
    bool canConvertString(string s, string t, int k) {
        if (s.length() != t.length()) {
            return false;
        }
        int diff = 0;
        for (int i = 0; i < s.length(); i++) {
            diff += (t[i] - s[i] + 26) % 26;
        }
        return diff <= k;
    }
};
